#include <stdbool.h>

#define fp float

typedef struct record {
	int value;
} record;

typedef struct knode {
	int location;
	int indices [DEFAULT_ORDER + 1];
	int  keys [DEFAULT_ORDER + 1];
	bool is_leaf;
	int num_keys;
} knode; 

void findK(	long height,
			knode *knodesD,
			long knodes_elem,
			record *recordsD,

			long *currKnodeD,
			long *offsetD,
			int *keysD, 
			record *ansD,
			int count,
			int order)
{
	// Each "bid" corresponds to one query
	// Each "thid" corresponds to one thread in the workgroup, here we simulate with OpenMP parallel for

	#pragma omp parallel for schedule(static)
	for (int bid = 0; bid < count; bid++) {
		long currKnode = currKnodeD[bid];
		long offset = offsetD[bid];
		int key = keysD[bid];
		record ans;
		ans.value = -1;

		for (int i = 0; i < height; i++) {
			// We simulate the threads in the workgroup with a loop over thid
			long new_offset = offset;
			for (int thid = 0; thid < order; thid++) {
				int key_thid = knodesD[currKnode].keys[thid];
				int key_thid1 = knodesD[currKnode].keys[thid+1];
				if (key_thid <= key && key_thid1 > key) {
					if (knodesD[offset].indices[thid] < knodes_elem) {
						new_offset = knodesD[offset].indices[thid];
					}
				}
			}
			offset = new_offset;
			currKnode = offset;
		}

		// After traversal, find the record with matching key
		for (int thid = 0; thid < order; thid++) {
			if (knodesD[currKnode].keys[thid] == key) {
				ans.value = recordsD[knodesD[currKnode].indices[thid]].value;
			}
		}
		ansD[bid] = ans;
	}
}

